def generate_content(city):
    """Generate unique content for a city from the pre-written database
    or construct it programmatically from city data."""
    slug = city["slug"]

    # Check pre-written content first
    if slug in CITY_CONTENT:
        return CITY_CONTENT[slug]

    # Programmatic generation using city-specific data (guaranteed unique per city)
    c = city
    profile_desc = {
        "oilgas":     f"energy production, industrial construction, and oil and gas infrastructure",
        "events":     f"live events, outdoor festivals, and hospitality",
        "coastal":    f"coastal tourism, waterfront development, and beach events",
        "college":    f"university athletics, campus construction, and student events",
        "tech":       f"technology sector growth, corporate campus construction, and innovation economy events",
        "suburban":   f"residential construction, community events, and commercial development",
        "government": f"military operations, government infrastructure, and public works",
    }.get(c["profile"], "construction and community events")

    para1 = (
        f"{c['name']}'s {c['county']} construction market is driven primarily by {profile_desc} "
        f"centered around {c['landmark1']} and extending throughout the {c['a1']} and {c['a2']} "
        f"development corridors. Active job sites in {c['a3']} and {c['a4']} keep a consistent "
        f"contractor workforce active in {c['county']} year-round, generating steady demand for "
        f"OSHA-compliant portable restrooms with documented weekly service schedules. FixPilot "
        f"maintains dedicated {c['county']} inventory to serve same-day construction deliveries "
        f"to {c['a1']}, {c['a2']}, and every active construction zone in the {c['name']} metro. "
        f"The {c['landmark1']} corridor represents the highest-demand construction zone in "
        f"{c['county']}, where projects range from commercial mixed-use development to "
        f"infrastructure upgrades along the {c['a5']} perimeter."
    )

    para2 = (
        f"{c['name']}'s event market is anchored by annual gatherings near {c['landmark2']} "
        f"and throughout the {c['a1']} and {c['a3']} entertainment corridors in {c['county']}. "
        f"The seasonal event calendar — outdoor concerts, community festivals, weddings at venues "
        f"near {c['landmark1']}, and {c['county']} civic gatherings — creates consistent premium "
        f"portable sanitation demand from spring through fall. Luxury restroom trailers for "
        f"upscale {c['a2']} and {c['a4']} event venues, standard units for large {c['county']} "
        f"community gatherings, and ADA-compliant options for public events near {c['landmark2']} "
        f"are all part of FixPilot's {c['name']} event service offering. The growing outdoor "
        f"wedding venue market in {c['a5']} and {c['a3']} reflects {c['name']}'s emergence as "
        f"a destination for outdoor celebrations throughout {c['county']}."
    )

    para3 = (
        f"Contractors working in {c['a1']}, event planners organizing gatherings near "
        f"{c['landmark2']}, and homeowners in {c['a4']} and {c['a5']} managing {c['name']} "
        f"renovation projects choose FixPilot over competitors because our {c['county']}-based "
        f"operation delivers local expertise that national vendors cannot provide. We know the "
        f"delivery windows, access requirements, and permit procedures for construction sites "
        f"near {c['landmark1']} and throughout the {c['a2']} development corridor. Our "
        f"{c['county']} dispatch team answers every call — no automated systems, no call "
        f"centers routing your {c['name']} order through another state. Same-day delivery "
        f"is standard, not a premium, for all of {c['county']}."
    )

    return f"{para1}\n\n{para2}\n\n{para3}"


def main():
    base = Path(".")
    dirs = sorted(p for p in base.iterdir()
                  if p.is_dir() and p.name.startswith("porta-potty-rental-"))

    def is_city_slug(slug):
        parts = slug.rsplit("-", 1)
        return len(parts) == 2 and parts[1].upper() in {
            "AL","AK","AZ","AR","CA","CO","CT","DE","FL","GA","HI","ID","IL",
            "IN","IA","KS","KY","LA","ME","MD","MA","MI","MN","MS","MO","MT",
            "NE","NV","NH","NJ","NM","NY","NC","ND","OH","OK","OR","PA","RI",
            "SC","SD","TN","TX","UT","VT","VA","WA","WV","WI","WY"
        }

    updated = skipped = written = 0
    for d in dirs:
        slug = d.name[len("porta-potty-rental-"):]
        if not is_city_slug(slug):
            continue
        page = d / "index.html"
        if not page.exists():
            continue
        city = get_city_data(slug)
        if city is None:
            skipped += 1
            continue

        cache_file = CACHE_DIR / f"{slug}.txt"
        if not cache_file.exists():
            content = generate_content(city)
            cache_file.write_text(content, encoding="utf-8")
            written += 1

        ai_text = cache_file.read_text(encoding="utf-8")
        html = page.read_text(encoding="utf-8")
        patched = inject_unique_content(html, city, ai_text)
        if patched != html:
            page.write_text(patched, encoding="utf-8")
            updated += 1
            print(f"  OK   {slug}")
        else:
            skipped += 1

    print(f"\nDone. Cache written: {written}  Pages updated: {updated}  Skipped: {skipped}")

if __name__ == "__main__":
    main()
